1	// ------------------------------------
2	// COMMS_TOP_REGBANK.v
3	//
4	// A simple register bank with local bus decoding created to support comms_top.v
5	//
6	// ------------------------------------
7	
8	module comms_top_regbank #(
9	   parameter LB_AWI = 24,
10	   parameter LB_DWI = 32
11	) (
12	   // Local bus interface
13	   input               lb_clk,
14	   input               lb_valid,
15	   input               lb_rnw,
16	   input [LB_AWI-1:0]  lb_addr,
17	   input [LB_DWI-1:0]  lb_wdata,
18	   input               lb_renable, // Ignored in this module
19	   output [LB_DWI-1:0] lb_rdata,
20	
21	   // Control registers in
22	   input [15:0]        rx_frame_counter_i,
23	   input [15:0]        txrx_latency_i,
24	   input [3:0]         ccrx_fault_i,
25	   input [15:0]        ccrx_fault_cnt_i,
26	   input               ccrx_los_i,
27	   input [3:0]         rx_protocol_ver_i,
28	   input [2:0]         rx_gateware_type_i,
29	   input [2:0]         rx_location_i,
30	   input [31:0]        rx_rev_id_i,
31	   input [31:0]        rx_data0_i,
32	   input [31:0]        rx_data1_i,
33	   input               rx_match0_i,
34	   input               rx_match1_i,
35	   input [15:0]        rx_err_cnt0_i,
36	   input [15:0]        rx_err_cnt1_i,
37	   input [8:0]         an_status_i,
38	   input [31:0]        ctr_mem_out_i,
39	
40	   // Control registers out
41	   output reg [2:0]    tx_location_o,
42	   output reg          tx_transmit_en_o,
43	   output reg          pgen_disable_o,
44	   output reg [4:0]    pgen_rate_o,
45	   output reg          pgen_test_mode_o,
46	   output reg [2:0]    pgen_inc_step_o,
47	   output reg [31:0]   pgen_usr_data_o
48	);
49	   `include "comms_features.vh"
50	   `include "comms_pack.vh"
51	
52	   localparam LOCAL_AWI = LB_AWI;
53	
54	   // Address map of read registers
55	   localparam [LOCAL_AWI-1:0] INFO0_RD_REG            = 0;
56	   localparam [LOCAL_AWI-1:0] INFO1_RD_REG            = 1;
57	   localparam [LOCAL_AWI-1:0] RX_FRAME_COUNTER_RD_REG = 2;
58	   localparam [LOCAL_AWI-1:0] TXRX_LATENCY_RD_REG     = 3;
59	   localparam [LOCAL_AWI-1:0] CCRX_FAULT_RD_REG       = 4;
60	   localparam [LOCAL_AWI-1:0] CCRX_FAULT_CNT_RD_REG   = 5;
61	   localparam [LOCAL_AWI-1:0] CCRX_LOS_RD_REG         = 6;
62	   localparam [LOCAL_AWI-1:0] RX_PROTOCOL_VER_RD_REG  = 7;
63	   localparam [LOCAL_AWI-1:0] RX_GATEWARE_TYPE_RD_REG = 8;
64	   localparam [LOCAL_AWI-1:0] RX_LOCATION_RD_REG      = 9;
65	   localparam [LOCAL_AWI-1:0] RX_REV_ID_RD_REG        = 10;
66	   localparam [LOCAL_AWI-1:0] RX_DATA0_RD_REG         = 11;
67	   localparam [LOCAL_AWI-1:0] RX_DATA1_RD_REG         = 12;
68	   localparam [LOCAL_AWI-1:0] RX_MATCH0_RD_REG        = 13;
69	   localparam [LOCAL_AWI-1:0] RX_MATCH1_RD_REG        = 14;
70	   localparam [LOCAL_AWI-1:0] RX_ERR_CNT0_RD_REG      = 15;
71	   localparam [LOCAL_AWI-1:0] RX_ERR_CNT1_RD_REG      = 16;
72	   localparam [LOCAL_AWI-1:0] AN_STATUS_RD_REG        = 17;
73	   localparam [LOCAL_AWI-1:0] CTR_MEM_OUT_RD_MEM      = 'h1????;
74	
75	
76	   // Address map of write registers
77	   localparam TX_LOCATION_WR_REG      = 0;
78	   localparam TX_TRANSMIT_EN_WR_REG   = 1;
79	   localparam PGEN_DISABLE_WR_REG     = 2;
80	   localparam PGEN_RATE_WR_REG        = 3;
81	   localparam PGEN_TEST_MODE_WR_REG   = 4;
82	   localparam PGEN_INC_STEP_WR_REG    = 5;
83	   localparam PGEN_USR_DAT_WR_REG     = 6;
84	
85	   reg [C_LBUS_DATA_WIDTH-1:0] lb_rdata_reg = 0;
86	
87	   reg [LOCAL_AWI-1:0] lb_addr_r=0;
88	   always @(posedge lb_clk) if (lb_valid && lb_rnw) lb_addr_r <= lb_addr;
89	
90	   // -------------------
91	   // Local Bus decoding
92	   // -------------------
93	   always @(posedge lb_clk) begin
94	      case (lb_addr_r[LOCAL_AWI-1:0])
95	         INFO0_RD_REG:            lb_rdata_reg <= "QF2P";
96	         INFO1_RD_REG:            lb_rdata_reg <= "COMM";
97	         RX_FRAME_COUNTER_RD_REG: lb_rdata_reg <= rx_frame_counter_i;
98	         TXRX_LATENCY_RD_REG:     lb_rdata_reg <= txrx_latency_i;
99	         CCRX_FAULT_RD_REG:       lb_rdata_reg <= ccrx_fault_i;
100	         CCRX_FAULT_CNT_RD_REG:   lb_rdata_reg <= ccrx_fault_cnt_i;
101	         CCRX_LOS_RD_REG:         lb_rdata_reg <= ccrx_los_i;
102	         RX_PROTOCOL_VER_RD_REG:  lb_rdata_reg <= rx_protocol_ver_i;
103	         RX_GATEWARE_TYPE_RD_REG: lb_rdata_reg <= rx_gateware_type_i;
104	         RX_LOCATION_RD_REG:      lb_rdata_reg <= rx_location_i;
